-- ============================================================
-- Pre-warmed exercise bank — vocab + grammar, B and C levels.
-- Generated by Claude Opus 4.7 (no OpenAI cost). Each row is a
-- single batch of 4 MC exercises matching the same payload shape
-- callOpenAI() returns for /api/generate and /api/grammar-drill.
--
-- Pedagogy:
--   - 4 question types per vocab batch: context / translate / gap / meaning
--   - Distractors chosen from typical Finnish-learner errors
--   - All 4 options share POS + number + gender
--   - Context sentences ≥ 6 words, yo-koe style
--   - Grammar batches target ONE phenomenon per batch (not mixed)
--
-- Level coverage (this file): B, C. M + E ship in a follow-up file.
-- ============================================================

-- ─── VOCAB · B · general vocabulary ──────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'B', 'general vocabulary', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Mi hermana trabaja en una tienda de ropa' — mitä tarkoittaa 'la tienda'?","context":"Mi hermana trabaja en una tienda de ropa en el centro.","options":["A) kauppa","B) koulu","C) toimisto","D) ravintola"],"correct":"A","explanation":"la tienda = kauppa. la escuela = koulu, la oficina = toimisto, el restaurante = ravintola."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'ystävä'?","context":"Mi mejor amigo vive en Madrid desde hace cinco años.","options":["A) el amigo","B) el hermano","C) el vecino","D) el compañero"],"correct":"A","explanation":"el amigo = ystävä. el hermano = veli, el vecino = naapuri, el compañero = kaveri/työkaveri."},
  {"id":3,"type":"gap","question":"Täydennä: 'Todas las mañanas ___ café con leche antes de ir al trabajo.'","context":"Todas las mañanas tomo café con leche antes de ir al trabajo.","options":["A) tomo","B) como","C) bebo","D) hago"],"correct":"A","explanation":"tomar café on vakiintunut ilmaus 'juoda kahvia'. beber käy mutta tomar on yleisempi aamiaisella; como = syön, hago = teen."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la calle'?","context":"Vivimos en una calle muy tranquila cerca del parque.","options":["A) katu","B) talo","C) puisto","D) kaupunki"],"correct":"A","explanation":"la calle = katu. la casa = talo, el parque = puisto, la ciudad = kaupunki."}
]$json$::jsonb, 1.0),

('vocab', 'B', 'general vocabulary', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Llegué tarde porque perdí el autobús' — mitä tarkoittaa 'el autobús'?","context":"Llegué tarde a clase porque perdí el autobús esta mañana.","options":["A) linja-auto","B) juna","C) metro","D) taksi"],"correct":"A","explanation":"el autobús = linja-auto. el tren = juna, el metro = metro, el taxi = taksi."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'kirja'?","context":"Siempre llevo un libro en mi mochila para leer en el tren.","options":["A) el libro","B) el cuaderno","C) el periódico","D) la revista"],"correct":"A","explanation":"el libro = kirja. el cuaderno = vihko, el periódico = sanomalehti, la revista = aikakauslehti."},
  {"id":3,"type":"gap","question":"Täydennä: 'No puedo dormir bien porque mi vecino ___ mucho ruido.'","context":"No puedo dormir bien porque mi vecino hace mucho ruido por la noche.","options":["A) hace","B) tiene","C) pone","D) da"],"correct":"A","explanation":"hacer ruido = 'pitää melua' on kiinteä ilmaus. Ei *tener ruido, ei *poner ruido."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'trabajar'?","context":"Mi padre trabaja en un hospital desde hace veinte años.","options":["A) tehdä työtä","B) opiskella","C) matkustaa","D) asua"],"correct":"A","explanation":"trabajar = tehdä työtä. estudiar = opiskella, viajar = matkustaa, vivir = asua."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · B · travel and transport ────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'B', 'travel and transport', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El vuelo a Barcelona tiene un retraso de dos horas' — mitä tarkoittaa 'el retraso'?","context":"El vuelo a Barcelona tiene un retraso de dos horas por mal tiempo.","options":["A) myöhästyminen","B) lähtö","C) laskeutuminen","D) peruutus"],"correct":"A","explanation":"el retraso = myöhästyminen, viivästys. la salida = lähtö, el aterrizaje = laskeutuminen, la cancelación = peruutus."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'matkalaukku'?","context":"Mi maleta es demasiado pesada para llevarla sola.","options":["A) la maleta","B) la mochila","C) el bolso","D) la caja"],"correct":"A","explanation":"la maleta = matkalaukku. la mochila = reppu, el bolso = käsilaukku, la caja = laatikko."},
  {"id":3,"type":"gap","question":"Täydennä: 'Antes de viajar hay que ___ el pasaporte en la oficina de policía.'","context":"Antes de viajar hay que renovar el pasaporte en la oficina de policía.","options":["A) renovar","B) comprar","C) vender","D) reservar"],"correct":"A","explanation":"renovar el pasaporte = uusia passi. comprar = ostaa, vender = myydä, reservar = varata (yleensä hotelli/lippu)."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el andén'?","context":"El tren sale del andén número cinco dentro de diez minutos.","options":["A) laituri","B) lippu","C) asema","D) vaunu"],"correct":"A","explanation":"el andén = (juna)laituri. el billete = lippu, la estación = asema, el vagón = vaunu."}
]$json$::jsonb, 1.0),

('vocab', 'B', 'travel and transport', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'He reservado una habitación doble para tres noches' — mitä tarkoittaa 'reservar'?","context":"He reservado una habitación doble para tres noches en un hotel del centro.","options":["A) varata","B) maksaa","C) etsiä","D) vuokrata"],"correct":"A","explanation":"reservar = varata (etukäteen). pagar = maksaa, buscar = etsiä, alquilar = vuokrata."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'lentokenttä'?","context":"El aeropuerto está a treinta kilómetros del centro de la ciudad.","options":["A) el aeropuerto","B) la estación","C) el puerto","D) la parada"],"correct":"A","explanation":"el aeropuerto = lentokenttä. la estación = (juna)asema, el puerto = satama, la parada = pysäkki."},
  {"id":3,"type":"gap","question":"Täydennä: 'Perdona, ¿me puedes decir dónde ___ la catedral?'","context":"Perdona, ¿me puedes decir dónde está la catedral?","options":["A) está","B) hay","C) es","D) tiene"],"correct":"A","explanation":"Tietyn kohteen sijainti → estar, ei hay. Hay la catedral on virheellinen (määräinen artikkeli + hay ei koskaan). ser ei ilmaise sijaintia."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el billete de ida y vuelta'?","context":"Compré un billete de ida y vuelta porque vuelvo el domingo.","options":["A) meno-paluulippu","B) kertalippu","C) kuukausilippu","D) ilmainen lippu"],"correct":"A","explanation":"billete de ida y vuelta = meno-paluulippu (ida = meno, vuelta = paluu). billete de ida = yhdensuuntainen."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · B · health and body ─────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'B', 'health and body', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Me duele mucho la cabeza desde ayer' — mitä tarkoittaa 'doler'?","context":"Me duele mucho la cabeza desde ayer por la noche.","options":["A) sattua","B) lyödä","C) näkyä","D) hoitaa"],"correct":"A","explanation":"doler = sattua (me duele la cabeza = päätäni särkee). golpear = lyödä, aparecer = näkyä, cuidar = hoitaa."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'sairaala'?","context":"Mi madre trabaja en el hospital como enfermera.","options":["A) el hospital","B) la farmacia","C) la consulta","D) la clínica"],"correct":"A","explanation":"el hospital = sairaala. la farmacia = apteekki, la consulta = vastaanotto, la clínica = klinikka (yleensä yksityinen)."},
  {"id":3,"type":"gap","question":"Täydennä: 'Para estar sano hay que ___ mucha fruta y verdura.'","context":"Para estar sano hay que comer mucha fruta y verdura todos los días.","options":["A) comer","B) beber","C) tomar","D) cocinar"],"correct":"A","explanation":"comer fruta y verdura = syödä (kiinteä ruoka). beber/tomar = juoda (neste), cocinar = kokata."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la fiebre'?","context":"No he ido al colegio porque tengo fiebre desde anoche.","options":["A) kuume","B) yskä","C) flunssa","D) väsymys"],"correct":"A","explanation":"la fiebre = kuume (tener fiebre). la tos = yskä, la gripe = flunssa, el cansancio = väsymys."}
]$json$::jsonb, 1.0),

('vocab', 'B', 'health and body', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Hago deporte tres veces por semana' — mitä tarkoittaa 'hacer deporte'?","context":"Hago deporte tres veces por semana para mantenerme en forma.","options":["A) urheilla","B) juosta","C) kävellä","D) nukkua"],"correct":"A","explanation":"hacer deporte = urheilla (yleisnimitys). correr = juosta, caminar = kävellä, dormir = nukkua."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'lääkäri'?","context":"Tengo cita con el médico esta tarde a las cinco.","options":["A) el médico","B) el enfermero","C) el dentista","D) el farmacéutico"],"correct":"A","explanation":"el médico = lääkäri. el enfermero = sairaanhoitaja, el dentista = hammaslääkäri, el farmacéutico = apteekkari."},
  {"id":3,"type":"gap","question":"Täydennä: 'Si te encuentras mal, deberías ___ al médico.'","context":"Si te encuentras mal, deberías ir al médico cuanto antes.","options":["A) ir","B) hablar","C) llamar","D) ver"],"correct":"A","explanation":"ir al médico = mennä lääkäriin on kiinteä ilmaus. llamar al médico = soittaa lääkärille (eri tilanne)."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la salud'?","context":"Lo más importante en la vida es tener buena salud.","options":["A) terveys","B) onnellisuus","C) elämä","D) ikä"],"correct":"A","explanation":"la salud = terveys. la felicidad = onnellisuus, la vida = elämä, la edad = ikä."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · B · society and politics ────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'B', 'society and politics', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Muchos jóvenes participan en las manifestaciones' — mitä tarkoittaa 'la manifestación'?","context":"Muchos jóvenes participan en las manifestaciones contra el cambio climático.","options":["A) mielenosoitus","B) kokous","C) juhla","D) keskustelu"],"correct":"A","explanation":"la manifestación = mielenosoitus. la reunión = kokous, la fiesta = juhla, el debate = keskustelu."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'äänestää'?","context":"En España se puede votar a partir de los dieciocho años.","options":["A) votar","B) elegir","C) decidir","D) opinar"],"correct":"A","explanation":"votar = äänestää (vaaleissa). elegir = valita, decidir = päättää, opinar = olla mielipide."},
  {"id":3,"type":"gap","question":"Täydennä: 'El gobierno ha ___ una nueva ley sobre el medio ambiente.'","context":"El gobierno ha aprobado una nueva ley sobre el medio ambiente el mes pasado.","options":["A) aprobado","B) comprado","C) hablado","D) escrito"],"correct":"A","explanation":"aprobar una ley = hyväksyä laki on kiinteä ilmaus. comprar/hablar/escribir eivät sovi lain yhteydessä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la igualdad'?","context":"La igualdad entre hombres y mujeres es un derecho fundamental.","options":["A) tasa-arvo","B) vapaus","C) demokratia","D) oikeus"],"correct":"A","explanation":"la igualdad = tasa-arvo. la libertad = vapaus, la democracia = demokratia, el derecho = oikeus."}
]$json$::jsonb, 1.0),

('vocab', 'B', 'society and politics', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Los inmigrantes buscan una vida mejor' — mitä tarkoittaa 'el inmigrante'?","context":"Los inmigrantes buscan una vida mejor para sus familias en Europa.","options":["A) maahanmuuttaja","B) matkailija","C) asukas","D) pakolainen"],"correct":"A","explanation":"el inmigrante = maahanmuuttaja. el turista = matkailija, el habitante = asukas, el refugiado = pakolainen (tarkempi termi)."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'yhteiskunta'?","context":"La sociedad española ha cambiado mucho en los últimos treinta años.","options":["A) la sociedad","B) la comunidad","C) el país","D) la población"],"correct":"A","explanation":"la sociedad = yhteiskunta. la comunidad = yhteisö, el país = maa, la población = väestö."},
  {"id":3,"type":"gap","question":"Täydennä: 'Los ciudadanos tienen derecho a ___ su opinión libremente.'","context":"Los ciudadanos tienen derecho a expresar su opinión libremente en una democracia.","options":["A) expresar","B) hablar","C) decir","D) comunicar"],"correct":"A","explanation":"expresar la opinión = ilmaista mielipide on yhteiskunnallinen vakioilmaus. Hablar/decir/comunicar ovat yleisempiä eivätkä istu tässä rekisterissä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la discriminación'?","context":"La discriminación por razones de género sigue siendo un problema grave.","options":["A) syrjintä","B) eroavaisuus","C) erilaisuus","D) konflikti"],"correct":"A","explanation":"la discriminación = syrjintä. la diferencia = ero(avaisuus), la diversidad = erilaisuus, el conflicto = konflikti."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · B · environment and nature ──────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'B', 'environment and nature', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Es importante reciclar el plástico y el papel' — mitä tarkoittaa 'reciclar'?","context":"Es importante reciclar el plástico y el papel para proteger el medio ambiente.","options":["A) kierrättää","B) polttaa","C) heittää pois","D) ostaa"],"correct":"A","explanation":"reciclar = kierrättää. quemar = polttaa, tirar = heittää pois, comprar = ostaa."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'ilmastonmuutos'?","context":"El cambio climático afecta a todo el planeta, no solo a algunos países.","options":["A) el cambio climático","B) el tiempo","C) la temperatura","D) la estación"],"correct":"A","explanation":"el cambio climático = ilmastonmuutos. el tiempo = sää, la temperatura = lämpötila, la estación = vuodenaika."},
  {"id":3,"type":"gap","question":"Täydennä: 'Hay que ___ agua porque es un recurso muy valioso.'","context":"Hay que ahorrar agua porque es un recurso muy valioso y limitado.","options":["A) ahorrar","B) gastar","C) comprar","D) beber"],"correct":"A","explanation":"ahorrar agua = säästää vettä. gastar = käyttää/kuluttaa, comprar = ostaa, beber = juoda."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el medio ambiente'?","context":"Todos debemos cuidar el medio ambiente para las futuras generaciones.","options":["A) ympäristö","B) maa","C) luonto","D) ilmasto"],"correct":"A","explanation":"el medio ambiente = ympäristö. el país = maa, la naturaleza = luonto, el clima = ilmasto."}
]$json$::jsonb, 1.0),

('vocab', 'B', 'environment and nature', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'La contaminación en las ciudades es un problema grave' — mitä tarkoittaa 'la contaminación'?","context":"La contaminación del aire en las ciudades grandes es un problema muy grave.","options":["A) saastuminen","B) meluhaitta","C) liikenne","D) rakentaminen"],"correct":"A","explanation":"la contaminación = saastuminen. el ruido = melu, el tráfico = liikenne, la construcción = rakentaminen."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'metsä'?","context":"Me encanta pasear por el bosque los fines de semana.","options":["A) el bosque","B) el campo","C) el parque","D) la montaña"],"correct":"A","explanation":"el bosque = metsä. el campo = maaseutu, el parque = puisto, la montaña = vuori."},
  {"id":3,"type":"gap","question":"Täydennä: 'Los árboles ___ oxígeno, por eso son tan importantes.'","context":"Los árboles producen oxígeno, por eso son tan importantes para nosotros.","options":["A) producen","B) beben","C) comen","D) crecen"],"correct":"A","explanation":"producir oxígeno = tuottaa happea. beber = juoda (ihminen), comer = syödä, crecer = kasvaa."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la basura'?","context":"Cada familia española produce unos veinte kilos de basura cada semana.","options":["A) roska","B) ruoka","C) tavara","D) aines"],"correct":"A","explanation":"la basura = roska. la comida = ruoka, las cosas = tavarat, el material = aines."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · B · culture and arts ────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'B', 'culture and arts', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'En el museo hay muchos cuadros famosos' — mitä tarkoittaa 'el cuadro'?","context":"En el museo del Prado hay muchos cuadros famosos de Velázquez y Goya.","options":["A) taulu","B) kirja","C) kuva","D) näyttely"],"correct":"A","explanation":"el cuadro = (taide)taulu. el libro = kirja, la foto = valokuva, la exposición = näyttely."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'elokuva'?","context":"La película empieza a las nueve en el cine del centro comercial.","options":["A) la película","B) el teatro","C) la serie","D) el programa"],"correct":"A","explanation":"la película = elokuva. el teatro = teatteri, la serie = sarja, el programa = ohjelma."},
  {"id":3,"type":"gap","question":"Täydennä: 'Me gusta ___ música mientras estudio.'","context":"Me gusta escuchar música mientras estudio para concentrarme mejor.","options":["A) escuchar","B) oír","C) tocar","D) cantar"],"correct":"A","explanation":"escuchar música = kuunnella musiikkia (aktiivinen kuuntelu). oír = kuulla (passiivinen), tocar = soittaa, cantar = laulaa."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la fiesta'?","context":"Las Fallas de Valencia es una fiesta muy famosa en toda España.","options":["A) juhla","B) loma","C) tapahtuma","D) näytös"],"correct":"A","explanation":"la fiesta = juhla. las vacaciones = loma, el evento = tapahtuma, el espectáculo = näytös."}
]$json$::jsonb, 1.0),

('vocab', 'B', 'culture and arts', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Mi grupo favorito da un concierto en Madrid' — mitä tarkoittaa 'el concierto'?","context":"Mi grupo favorito da un concierto en Madrid el próximo sábado por la noche.","options":["A) konsertti","B) esitys","C) festivaali","D) disko"],"correct":"A","explanation":"el concierto = konsertti. la actuación = esiintyminen, el festival = festivaali, la discoteca = disko."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'kirjailija'?","context":"Gabriel García Márquez es un escritor colombiano muy famoso.","options":["A) el escritor","B) el lector","C) el pintor","D) el actor"],"correct":"A","explanation":"el escritor = kirjailija. el lector = lukija, el pintor = taiteilija, el actor = näyttelijä."},
  {"id":3,"type":"gap","question":"Täydennä: 'El flamenco es un ___ tradicional de Andalucía.'","context":"El flamenco es un baile tradicional de Andalucía con mucha pasión.","options":["A) baile","B) canción","C) instrumento","D) vestido"],"correct":"A","explanation":"el baile = tanssi (flamenco = tanssi). la canción = laulu, el instrumento = soitin, el vestido = mekko."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la novela'?","context":"Acabo de leer una novela policíaca que me ha gustado mucho.","options":["A) romaani","B) runo","C) näytelmä","D) tarina"],"correct":"A","explanation":"la novela = romaani. el poema = runo, la obra de teatro = näytelmä, el cuento = (lyhyt) tarina."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · B · work and economy ────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'B', 'work and economy', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Busco un trabajo a tiempo parcial' — mitä tarkoittaa 'a tiempo parcial'?","context":"Busco un trabajo a tiempo parcial porque también estudio por las mañanas.","options":["A) osa-aikaisesti","B) kokopäiväisesti","C) vapaaehtoisesti","D) kausiluonteisesti"],"correct":"A","explanation":"a tiempo parcial = osa-aikaisesti. a tiempo completo = kokopäiväisesti, voluntario = vapaaehtoinen, temporal = tilapäinen."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'palkka'?","context":"Mi sueldo no es muy alto pero me alcanza para vivir bien.","options":["A) el sueldo","B) el precio","C) el dinero","D) la factura"],"correct":"A","explanation":"el sueldo = palkka. el precio = hinta, el dinero = raha, la factura = lasku."},
  {"id":3,"type":"gap","question":"Täydennä: 'He mandado mi ___ a diez empresas diferentes.'","context":"He mandado mi currículum a diez empresas diferentes pero todavía no he recibido respuesta.","options":["A) currículum","B) carta","C) trabajo","D) empresa"],"correct":"A","explanation":"mandar el currículum = lähettää CV. la carta = kirje, el trabajo = työ, la empresa = yritys."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el paro'?","context":"El paro juvenil en España es todavía un problema muy grande.","options":["A) työttömyys","B) palkka","C) loma","D) tauko"],"correct":"A","explanation":"el paro = työttömyys (Espanjassa). el sueldo = palkka, las vacaciones = loma, la pausa = tauko."}
]$json$::jsonb, 1.0),

('vocab', 'B', 'work and economy', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Quiero abrir mi propia empresa en el futuro' — mitä tarkoittaa 'la empresa'?","context":"Quiero abrir mi propia empresa en el futuro cuando tenga suficiente experiencia.","options":["A) yritys","B) työpaikka","C) kauppa","D) tehdas"],"correct":"A","explanation":"la empresa = yritys. el puesto de trabajo = työpaikka (asema), la tienda = kauppa, la fábrica = tehdas."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'työhaastattelu'?","context":"Tengo una entrevista de trabajo mañana por la mañana a las diez.","options":["A) la entrevista de trabajo","B) la reunión","C) el examen","D) la conversación"],"correct":"A","explanation":"la entrevista de trabajo = työhaastattelu. la reunión = kokous, el examen = koe, la conversación = keskustelu."},
  {"id":3,"type":"gap","question":"Täydennä: 'En verano muchos estudiantes hacen ___ en empresas para ganar experiencia.'","context":"En verano muchos estudiantes hacen prácticas en empresas para ganar experiencia laboral.","options":["A) prácticas","B) vacaciones","C) exámenes","D) deberes"],"correct":"A","explanation":"hacer prácticas = suorittaa harjoittelu. las vacaciones = loma, los exámenes = kokeet, los deberes = läksyt."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'jubilarse'?","context":"Mi abuelo se jubiló el año pasado después de cuarenta años de trabajo.","options":["A) jäädä eläkkeelle","B) lopettaa työ","C) muuttaa","D) sairastua"],"correct":"A","explanation":"jubilarse = jäädä eläkkeelle. dejar el trabajo = lopettaa työ (vapaaehtoisesti), mudarse = muuttaa, enfermarse = sairastua."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · C · general vocabulary ──────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'C', 'general vocabulary', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El asunto me parece bastante complicado' — mitä tarkoittaa 'el asunto'?","context":"El asunto me parece bastante complicado y necesita más reflexión.","options":["A) asia","B) tapahtuma","C) ongelma","D) uutinen"],"correct":"A","explanation":"el asunto = asia (neutraali). el evento = tapahtuma, el problema = ongelma, la noticia = uutinen."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'saavuttaa'?","context":"Ha logrado sus objetivos gracias al trabajo duro y a la constancia.","options":["A) lograr","B) llegar","C) conseguir","D) alcanzar"],"correct":"A","explanation":"lograr = saavuttaa (tavoite, usein abstrakti). llegar = saapua, conseguir = saada, alcanzar = saavuttaa (fyysinen). C-tasolla lograr on tavallisempi teksteissä."},
  {"id":3,"type":"gap","question":"Täydennä: 'A pesar de las dificultades, siguió ___ su sueño hasta el final.'","context":"A pesar de las dificultades, siguió persiguiendo su sueño hasta el final.","options":["A) persiguiendo","B) mirando","C) hablando","D) escribiendo"],"correct":"A","explanation":"perseguir un sueño = tavoitella unelmaa (kuvaannollinen). Mirar/hablar/escribir eivät sovi sumun kanssa."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'aprovechar'?","context":"Hay que aprovechar todas las oportunidades que nos ofrece la vida.","options":["A) hyödyntää","B) menettää","C) tarjota","D) hylätä"],"correct":"A","explanation":"aprovechar = hyödyntää. perder = menettää, ofrecer = tarjota, rechazar = hylätä."}
]$json$::jsonb, 1.0),

('vocab', 'C', 'general vocabulary', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Tengo la sensación de que algo va mal' — mitä tarkoittaa 'la sensación'?","context":"Tengo la sensación de que algo va mal con el proyecto este mes.","options":["A) tunne","B) aisti","C) mielipide","D) ajatus"],"correct":"A","explanation":"la sensación = tunne (tunnelma). el sentido = aisti, la opinión = mielipide, la idea = ajatus."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'parantaa' (esim. taitoja)?","context":"Quiere mejorar su nivel de español antes del examen.","options":["A) mejorar","B) aumentar","C) cambiar","D) desarrollar"],"correct":"A","explanation":"mejorar = parantaa (taso, laatu). aumentar = lisätä (määrä), cambiar = muuttaa, desarrollar = kehittää (projekti)."},
  {"id":3,"type":"gap","question":"Täydennä: 'No ___ cuenta de lo importante que era hasta que fue demasiado tarde.'","context":"No me di cuenta de lo importante que era hasta que fue demasiado tarde.","options":["A) me di","B) me puse","C) me hice","D) me quedé"],"correct":"A","explanation":"darse cuenta de = tajuta, huomata — kiinteä refleksiivi-ilmaus. Muut eivät sovi rakenteeseen."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el apoyo'?","context":"Siempre he contado con el apoyo incondicional de mi familia.","options":["A) tuki","B) neuvo","C) apu","D) rakkaus"],"correct":"A","explanation":"el apoyo = tuki (henkinen, taloudellinen). el consejo = neuvo, la ayuda = apu (konkreettinen), el amor = rakkaus."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · C · travel and transport ────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'C', 'travel and transport', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El turismo sostenible es cada vez más popular' — mitä tarkoittaa 'sostenible'?","context":"El turismo sostenible es cada vez más popular entre los jóvenes europeos.","options":["A) kestävä","B) halpa","C) nopea","D) turvallinen"],"correct":"A","explanation":"sostenible = kestävä (ympäristön kannalta). barato = halpa, rápido = nopea, seguro = turvallinen."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'varaus' (esim. hotelli)?","context":"Hice la reserva del hotel a través de una página web española.","options":["A) la reserva","B) el billete","C) la compra","D) el pedido"],"correct":"A","explanation":"la reserva = varaus. el billete = lippu, la compra = osto, el pedido = tilaus."},
  {"id":3,"type":"gap","question":"Täydennä: 'La compañía aérea nos ___ un vuelo alternativo sin coste extra.'","context":"La compañía aérea nos ofreció un vuelo alternativo sin coste extra después de la cancelación.","options":["A) ofreció","B) pidió","C) ordenó","D) prohibió"],"correct":"A","explanation":"ofrecer un vuelo = tarjota lento. pedir = pyytää, ordenar = määrätä, prohibir = kieltää."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'desplazarse'?","context":"La mayoría de los madrileños se desplazan al trabajo en transporte público.","options":["A) siirtyä","B) asua","C) työskennellä","D) myöhästyä"],"correct":"A","explanation":"desplazarse = siirtyä, liikkua (paikasta toiseen). vivir = asua, trabajar = työskennellä, retrasarse = myöhästyä."}
]$json$::jsonb, 1.0),

('vocab', 'C', 'travel and transport', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El aeropuerto de Barajas es uno de los más transitados de Europa' — mitä tarkoittaa 'transitado'?","context":"El aeropuerto de Barajas es uno de los más transitados de Europa en temporada alta.","options":["A) ruuhkainen","B) moderni","C) suuri","D) vanha"],"correct":"A","explanation":"transitado = ruuhkainen, vilkas. moderno = moderni, grande = suuri, antiguo = vanha."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'ylibooking'?","context":"La aerolínea tuvo un problema de overbooking y algunos pasajeros no pudieron embarcar.","options":["A) el overbooking / sobreventa","B) el retraso","C) la cancelación","D) la reserva"],"correct":"A","explanation":"overbooking/sobreventa = ylibooking. el retraso = myöhästyminen, la cancelación = peruutus, la reserva = varaus."},
  {"id":3,"type":"gap","question":"Täydennä: 'Los viajeros deben ___ sus maletas antes del vuelo.'","context":"Los viajeros deben facturar sus maletas antes del vuelo en el mostrador correspondiente.","options":["A) facturar","B) pagar","C) recoger","D) enviar"],"correct":"A","explanation":"facturar las maletas = kirjata matkatavarat. pagar = maksaa, recoger = hakea, enviar = lähettää."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el itinerario'?","context":"Antes de viajar siempre preparo un itinerario detallado de las visitas.","options":["A) matkasuunnitelma","B) matkalippu","C) matkaopas","D) matkavakuutus"],"correct":"A","explanation":"el itinerario = matkasuunnitelma. el billete = lippu, la guía = matkaopas, el seguro = vakuutus."}
]$json$::jsonb, 1.0);

-- ─── VOCAB · C · health and body ─────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'C', 'health and body', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'La salud mental es tan importante como la física' — mitä tarkoittaa 'la salud mental'?","context":"La salud mental es tan importante como la física, aunque a veces se ignora.","options":["A) mielenterveys","B) äly","C) muisti","D) tunne"],"correct":"A","explanation":"la salud mental = mielenterveys. la inteligencia = äly, la memoria = muisti, la emoción = tunne."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'stressi'?","context":"Mucha gente sufre estrés por el trabajo y los estudios.","options":["A) el estrés","B) la ansiedad","C) la depresión","D) la tensión"],"correct":"A","explanation":"el estrés = stressi. la ansiedad = ahdistus, la depresión = masennus, la tensión = jännitys (lihas tai tilanne)."},
  {"id":3,"type":"gap","question":"Täydennä: 'Una dieta ___ es fundamental para mantener un peso saludable.'","context":"Una dieta equilibrada es fundamental para mantener un peso saludable y tener energía.","options":["A) equilibrada","B) larga","C) corta","D) difícil"],"correct":"A","explanation":"dieta equilibrada = tasapainoinen ruokavalio on kiinteä ilmaus. larga/corta/difícil eivät sovi."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el bienestar'?","context":"Cuidar nuestro bienestar físico y emocional debería ser una prioridad.","options":["A) hyvinvointi","B) sairaus","C) kunto","D) elämäntapa"],"correct":"A","explanation":"el bienestar = hyvinvointi. la enfermedad = sairaus, la forma = kunto, el estilo de vida = elämäntapa."}
]$json$::jsonb, 1.0),

('vocab', 'C', 'health and body', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Los adolescentes pasan demasiado tiempo delante de las pantallas' — mitä tarkoittaa 'la pantalla'?","context":"Los adolescentes pasan demasiado tiempo delante de las pantallas de móviles y ordenadores.","options":["A) näyttö","B) televisio","C) kirja","D) peli"],"correct":"A","explanation":"la pantalla = näyttö (yleistermi). la televisión = televisio, el libro = kirja, el juego = peli."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'ehkäistä' (esim. sairaus)?","context":"Hacer ejercicio regularmente ayuda a prevenir muchas enfermedades.","options":["A) prevenir","B) curar","C) tratar","D) evitar"],"correct":"A","explanation":"prevenir = ehkäistä (ennalta). curar = parantaa, tratar = hoitaa, evitar = välttää."},
  {"id":3,"type":"gap","question":"Täydennä: 'El médico me ___ tomar una pastilla dos veces al día.'","context":"El médico me recetó tomar una pastilla dos veces al día durante una semana.","options":["A) recetó","B) recomendó","C) dijo","D) escribió"],"correct":"A","explanation":"recetar = määrätä (lääke). recomendar = suositella, decir = sanoa, escribir = kirjoittaa. Lääkärille ominaista 'recetar medicamentos'."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el agotamiento'?","context":"Después de tantas horas de trabajo sintió un agotamiento total.","options":["A) uupumus","B) suru","C) ärsytys","D) sairaus"],"correct":"A","explanation":"el agotamiento = uupumus, loppuunpalaminen. la tristeza = suru, la irritación = ärsytys, la enfermedad = sairaus."}
]$json$::jsonb, 1.0);

