INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'C', 'society and politics', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'La desigualdad económica sigue aumentando en muchos países' — mitä tarkoittaa 'la desigualdad'?","context":"La desigualdad económica sigue aumentando en muchos países desarrollados.","options":["A) eriarvoisuus","B) köyhyys","C) tulot","D) talouskasvu"],"correct":"A","explanation":"la desigualdad = eriarvoisuus. la pobreza = köyhyys, los ingresos = tulot, el crecimiento económico = talouskasvu."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'puolustaa' (esim. oikeuksia)?","context":"Las organizaciones defienden los derechos de las minorías.","options":["A) defender","B) atacar","C) proteger","D) apoyar"],"correct":"A","explanation":"defender = puolustaa (argumentein/oikeudellisesti). atacar = hyökätä, proteger = suojella (konkreettisesti), apoyar = tukea."},
  {"id":3,"type":"gap","question":"Täydennä: 'El presidente ___ un discurso muy importante ante el parlamento.'","context":"El presidente pronunció un discurso muy importante ante el parlamento el martes pasado.","options":["A) pronunció","B) dijo","C) leyó","D) escribió"],"correct":"A","explanation":"pronunciar un discurso = pitää puhe on vakiintunut kollokaatio. decir/leer/escribir eivät sovi puheen pitämiseen virallisessa rekisterissä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la libertad de expresión'?","context":"La libertad de expresión es uno de los pilares de toda democracia.","options":["A) sananvapaus","B) uskonnonvapaus","C) äänioikeus","D) kokoontumisvapaus"],"correct":"A","explanation":"libertad de expresión = sananvapaus. libertad de religión = uskonnonvapaus, derecho al voto = äänioikeus, libertad de reunión = kokoontumisvapaus."}
]$json$::jsonb, 1.0),

('vocab', 'C', 'society and politics', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Las redes sociales influyen mucho en la opinión pública' — mitä tarkoittaa 'las redes sociales'?","context":"Las redes sociales influyen mucho en la opinión pública, sobre todo entre los jóvenes.","options":["A) sosiaalinen media","B) internet","C) televisio","D) lehdistö"],"correct":"A","explanation":"las redes sociales = sosiaalinen media. internet = internet, la televisión = televisio, la prensa = lehdistö."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'maahanmuutto'?","context":"La inmigración es un tema que genera muchos debates políticos.","options":["A) la inmigración","B) la emigración","C) el turismo","D) la población"],"correct":"A","explanation":"la inmigración = maahanmuutto. la emigración = maastamuutto (eri suunta!), el turismo = matkailu, la población = väestö."},
  {"id":3,"type":"gap","question":"Täydennä: 'El gobierno ___ nuevas medidas contra la corrupción.'","context":"El gobierno ha adoptado nuevas medidas contra la corrupción en la administración pública.","options":["A) ha adoptado","B) ha comprado","C) ha hablado","D) ha escuchado"],"correct":"A","explanation":"adoptar medidas = ryhtyä toimiin on hallinnollinen kollokaatio. comprar/hablar/escuchar eivät sovi toimenpiteiden yhteydessä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la manifestación'?","context":"Miles de personas participaron en la manifestación a favor del clima.","options":["A) mielenosoitus","B) juhla","C) kokous","D) mielipide"],"correct":"A","explanation":"la manifestación = mielenosoitus. la fiesta = juhla, la reunión = kokous, la opinión = mielipide."}
]$json$::jsonb, 1.0);

