INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('vocab', 'C', 'environment and nature', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Los recursos naturales se están agotando rápidamente' — mitä tarkoittaa 'agotarse'?","context":"Los recursos naturales del planeta se están agotando rápidamente debido al consumo excesivo.","options":["A) ehtyä","B) lisääntyä","C) säilyä","D) vähentyä"],"correct":"A","explanation":"agotarse = ehtyä (käytetään loppuun). aumentar = lisääntyä, conservarse = säilyä, disminuir = vähentyä."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'uusiutuva energia'?","context":"La energía renovable es la alternativa más ecológica al petróleo.","options":["A) la energía renovable","B) la energía nuclear","C) la electricidad","D) el combustible"],"correct":"A","explanation":"la energía renovable = uusiutuva energia. la energía nuclear = ydinenergia, la electricidad = sähkö, el combustible = polttoaine."},
  {"id":3,"type":"gap","question":"Täydennä: 'Es fundamental ___ la biodiversidad del planeta para las futuras generaciones.'","context":"Es fundamental preservar la biodiversidad del planeta para las futuras generaciones.","options":["A) preservar","B) consumir","C) explotar","D) ignorar"],"correct":"A","explanation":"preservar la biodiversidad = suojella biodiversiteettiä. consumir = kuluttaa, explotar = hyväksikäyttää, ignorar = jättää huomiotta."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la sequía'?","context":"España sufre cada año sequías más largas e intensas por el cambio climático.","options":["A) kuivuus","B) tulva","C) myrsky","D) kuumuus"],"correct":"A","explanation":"la sequía = kuivuus. la inundación = tulva, la tormenta = myrsky, el calor = kuumuus."}
]$json$::jsonb, 1.0),

('vocab', 'C', 'environment and nature', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El calentamiento global afecta a todo el planeta' — mitä tarkoittaa 'el calentamiento global'?","context":"El calentamiento global afecta a todo el planeta y ya se nota en el deshielo polar.","options":["A) ilmaston lämpeneminen","B) sääilmiö","C) kesäkuumuus","D) saastuminen"],"correct":"A","explanation":"el calentamiento global = ilmaston lämpeneminen (tarkempi kuin cambio climático). el fenómeno meteorológico = sääilmiö, la contaminación = saastuminen."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'uhanalainen' (laji)?","context":"El lince ibérico es una especie en peligro de extinción.","options":["A) en peligro de extinción","B) protegido","C) raro","D) salvaje"],"correct":"A","explanation":"en peligro de extinción = uhanalainen, sukupuuton partaalla. protegido = suojeltu, raro = harvinainen, salvaje = villi."},
  {"id":3,"type":"gap","question":"Täydennä: 'Los científicos ___ sobre los efectos del cambio climático desde hace décadas.'","context":"Los científicos advierten sobre los efectos del cambio climático desde hace décadas.","options":["A) advierten","B) dicen","C) gritan","D) piensan"],"correct":"A","explanation":"advertir sobre = varoittaa jostakin (virallinen rekisteri). decir = sanoa (neutraali), gritar = huutaa, pensar = ajatella."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el consumo responsable'?","context":"El consumo responsable es la mejor manera de reducir nuestra huella ecológica.","options":["A) vastuullinen kulutus","B) halpa ostaminen","C) kierrätys","D) säästäminen"],"correct":"A","explanation":"consumo responsable = vastuullinen kulutus. comprar barato = ostaa halvalla, reciclaje = kierrätys, ahorro = säästäminen."}
]$json$::jsonb, 1.0);

