('vocab', 'C', 'culture and arts', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'La obra refleja la realidad social de la época' — mitä tarkoittaa 'la obra'?","context":"La obra refleja la realidad social de la época en la que fue escrita.","options":["A) teos","B) työ","C) tehdas","D) toiminta"],"correct":"A","explanation":"la obra = teos (kirjallinen/taiteellinen). el trabajo = työ, la fábrica = tehdas, la acción = toiminta."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'perinne'?","context":"La corrida de toros es una tradición muy controvertida en España.","options":["A) la tradición","B) la costumbre","C) la cultura","D) la historia"],"correct":"A","explanation":"la tradición = perinne. la costumbre = tapa, la cultura = kulttuuri, la historia = historia."},
  {"id":3,"type":"gap","question":"Täydennä: 'El artista ha ___ una colección impresionante a lo largo de su carrera.'","context":"El artista ha creado una colección impresionante a lo largo de su carrera de cuarenta años.","options":["A) creado","B) vendido","C) comprado","D) visto"],"correct":"A","explanation":"crear una colección = luoda kokoelma. vender = myydä, comprar = ostaa, ver = nähdä."},
