('vocab', 'C', 'work and economy', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'Los sueldos de los jóvenes apenas cubren los gastos básicos' — mitä tarkoittaa 'los gastos'?","context":"Los sueldos de los jóvenes españoles apenas cubren los gastos básicos de la vida diaria.","options":["A) kulut","B) tulot","C) säästöt","D) velat"],"correct":"A","explanation":"los gastos = menot, kulut. los ingresos = tulot, los ahorros = säästöt, las deudas = velat."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'palkata'?","context":"La empresa quiere contratar a veinte nuevos empleados este año.","options":["A) contratar","B) despedir","C) buscar","D) conocer"],"correct":"A","explanation":"contratar = palkata. despedir = irtisanoa, buscar = etsiä, conocer = tuntea."},
  {"id":3,"type":"gap","question":"Täydennä: 'Muchas pequeñas empresas ___ por la crisis económica del año pasado.'","context":"Muchas pequeñas empresas quebraron por la crisis económica del año pasado.","options":["A) quebraron","B) crecieron","C) abrieron","D) vendieron"],"correct":"A","explanation":"quebrar = mennä konkurssiin. crecer = kasvaa, abrir = avata, vender = myydä."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'el emprendedor'?","context":"Un emprendedor necesita valor y creatividad para empezar su propio negocio.","options":["A) yrittäjä","B) johtaja","C) työntekijä","D) asiakas"],"correct":"A","explanation":"el emprendedor = yrittäjä (erit. aloittava). el jefe = johtaja, el empleado = työntekijä, el cliente = asiakas."}
]$json$::jsonb, 1.0),

('vocab', 'C', 'work and economy', 'spanish', $json$[
  {"id":1,"type":"context","question":"Lauseessa 'El teletrabajo se ha convertido en una opción habitual' — mitä tarkoittaa 'el teletrabajo'?","context":"El teletrabajo se ha convertido en una opción habitual para muchos profesionales.","options":["A) etätyö","B) osa-aikatyö","C) ylityö","D) kausityö"],"correct":"A","explanation":"el teletrabajo = etätyö. el trabajo a tiempo parcial = osa-aikatyö, las horas extras = ylityö, el trabajo temporal = kausityö."},
  {"id":2,"type":"translate","question":"Miten sanotaan espanjaksi: 'kilpailu' (esim. markkinoilla)?","context":"La competencia entre las grandes empresas es cada vez más dura.","options":["A) la competencia","B) el contrato","C) el acuerdo","D) el mercado"],"correct":"A","explanation":"la competencia = kilpailu. el contrato = sopimus, el acuerdo = sopimus (molemmin puolin), el mercado = markkinat."},
  {"id":3,"type":"gap","question":"Täydennä: 'Los trabajadores exigen mejores condiciones ___ desde hace meses.'","context":"Los trabajadores exigen mejores condiciones laborales desde hace meses sin recibir respuesta.","options":["A) laborales","B) económicas","C) sociales","D) legales"],"correct":"A","explanation":"condiciones laborales = työolot on vakiintunut ilmaus. económicas/sociales/legales viittaavat eri asioihin."},
  {"id":4,"type":"meaning","question":"¿Qué significa 'la jornada laboral'?","context":"En Francia la jornada laboral es de treinta y cinco horas a la semana.","options":["A) työaika","B) työmatka","C) työkalu","D) työsopimus"],"correct":"A","explanation":"la jornada laboral = työaika/työpäivä. el viaje de trabajo = työmatka, la herramienta = työkalu, el contrato laboral = työsopimus."}
]$json$::jsonb, 1.0);

