-- GRAMMAR — 6 topics × 2 levels × 2 batches = 24 batches
-- ============================================================

-- ─── GRAMMAR · B · ser_estar ─────────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('grammar', 'B', 'ser_estar', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Mi hermana ___ profesora en un instituto.'","context":"Mi hermana es profesora en un instituto de Madrid desde hace tres años.","options":["A) es","B) está","C) hay","D) tiene"],"correct":"A","explanation":"Ammatti on pysyvä ominaisuus → ser. estar ei käy identiteetin/ammatin yhteydessä.","rule":"ser_identidad"},
  {"id":2,"type":"gap","question":"Täydennä: 'La sopa ___ muy caliente, ten cuidado.'","context":"La sopa está muy caliente, ten cuidado al tomarla.","options":["A) está","B) es","C) hay","D) tiene"],"correct":"A","explanation":"Tilapäinen tila (tällä hetkellä kuuma) → estar. 'La sopa es caliente' = kuumuus on sopan ominaisuus (esim. ruokalaji).","rule":"estar_estado"},
  {"id":3,"type":"gap","question":"Täydennä: '¿Dónde ___ mis llaves? No las encuentro.'","context":"¿Dónde están mis llaves? No las encuentro en ninguna parte.","options":["A) están","B) son","C) hay","D) tienen"],"correct":"A","explanation":"Tietyn esineen sijainti → estar, ei koskaan ser. hay + määräinen artikkeli olisi virhe.","rule":"estar_ubicacion"},
  {"id":4,"type":"gap","question":"Täydennä: '¿De dónde ___ tú? — Soy de Helsinki.'","context":"¿De dónde eres tú? — Soy de Helsinki, pero ahora vivo en Sevilla.","options":["A) eres","B) estás","C) hay","D) tienes"],"correct":"A","explanation":"Alkuperä on pysyvä → ser de. estar de tarkoittaa 'olla tilapäisesti' (esim. estar de vacaciones).","rule":"ser_origen"}
]$json$::jsonb, 1.0),

('grammar', 'B', 'ser_estar', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Hoy ___ muy cansado porque he dormido poco.'","context":"Hoy estoy muy cansado porque he dormido muy poco esta noche.","options":["A) estoy","B) soy","C) hay","D) tengo"],"correct":"A","explanation":"Tilapäinen fyysinen tila → estar. 'Soy cansado' tarkoittaisi 'olen raskas/rasittava ihminen' (eri merkitys).","rule":"estar_estado_fisico"},
  {"id":2,"type":"gap","question":"Täydennä: 'La película ___ muy divertida, te la recomiendo.'","context":"La película es muy divertida, te la recomiendo de verdad.","options":["A) es","B) está","C) hay","D) tiene"],"correct":"A","explanation":"Elokuvan ominaisuus (luonteenpiirre) → ser. estar divertido tarkoittaisi 'on hauskalla tuulella'.","rule":"ser_caracteristica"},
  {"id":3,"type":"gap","question":"Täydennä: 'El examen ___ mañana a las diez en el aula 3.'","context":"El examen es mañana a las diez en el aula número tres.","options":["A) es","B) está","C) hay","D) tiene"],"correct":"A","explanation":"Tapahtuman aika + paikka → ser (ei estar!). 'El examen está en el aula 3' olisi virhe — estar + paikka käy vain konkreettisille esineille, ei tapahtumille.","rule":"ser_evento"},
  {"id":4,"type":"gap","question":"Täydennä: 'Mis padres ___ de viaje esta semana.'","context":"Mis padres están de viaje esta semana en Portugal.","options":["A) están","B) son","C) hay","D) tienen"],"correct":"A","explanation":"'estar de + nomini' = olla tilapäisessä tilanteessa (de viaje, de vacaciones, de visita). Ser de viaje ei ole olemassa.","rule":"estar_de_locución"}
]$json$::jsonb, 1.0);

-- ─── GRAMMAR · B · hay_estar ─────────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('grammar', 'B', 'hay_estar', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'En mi habitación ___ una cama y un armario.'","context":"En mi habitación hay una cama y un armario grande junto a la ventana.","options":["A) hay","B) está","C) están","D) son"],"correct":"A","explanation":"Olemassaolo yleisesti (epämääräinen artikkeli 'una') → hay. estar vaatisi määrätyn esineen (la cama de mi hermano).","rule":"hay_existencia"},
  {"id":2,"type":"gap","question":"Täydennä: 'La catedral ___ en el centro de la ciudad.'","context":"La catedral está en el centro histórico de la ciudad, cerca de la plaza.","options":["A) está","B) hay","C) es","D) tiene"],"correct":"A","explanation":"Tietyn, määrätyn kohteen sijainti → estar. 'Hay la catedral' on virhe — hay ei KOSKAAN ota määräistä artikkelia.","rule":"estar_ubicacion_definida"},
  {"id":3,"type":"gap","question":"Täydennä: 'En esta playa ___ muchas gaviotas por la mañana.'","context":"En esta playa hay muchas gaviotas por la mañana buscando comida.","options":["A) hay","B) están","C) son","D) tienen"],"correct":"A","explanation":"Olemassaolo ilman määrättyä viittausta → hay. 'Están las gaviotas' toimisi vain jos olisi jo mainittu tietyt lokit.","rule":"hay_existencia_plural"},
  {"id":4,"type":"gap","question":"Täydennä: '¿Dónde ___ el baño? No lo encuentro.'","context":"¿Dónde está el baño? No lo encuentro en este restaurante.","options":["A) está","B) hay","C) es","D) son"],"correct":"A","explanation":"Määrätyn esineen (el baño) sijainti → estar. Hay kysyisi 'onko tässä vessaa', estar kysyy 'missä tietty vessa on'.","rule":"estar_ubicacion_pregunta"}
]$json$::jsonb, 1.0),

('grammar', 'B', 'hay_estar', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'En la nevera no ___ leche, tenemos que comprar.'","context":"En la nevera no hay leche, tenemos que comprar en el supermercado.","options":["A) hay","B) está","C) es","D) tiene"],"correct":"A","explanation":"Olemassaolon kieltäminen (ei mitään maitoa) → hay. 'No está la leche' tarkoittaisi että tietty maito puuttuu jostakin paikasta.","rule":"hay_no_existe"},
  {"id":2,"type":"gap","question":"Täydennä: 'Madrid ___ en el centro de España.'","context":"Madrid está en el centro de España, a unos trescientos kilómetros de Valencia.","options":["A) está","B) hay","C) es","D) tiene"],"correct":"A","explanation":"Kaupungin (yksilöity paikannimi) sijainti → estar. 'Hay Madrid' on täysin mahdoton — hay + erisnimi ei toimi.","rule":"estar_ubicacion_ciudad"},
  {"id":3,"type":"gap","question":"Täydennä: 'En el salón ___ dos sofás nuevos que compramos ayer.'","context":"En el salón hay dos sofás nuevos que compramos ayer en IKEA.","options":["A) hay","B) están","C) son","D) tienen"],"correct":"A","explanation":"Epämäärä lukumäärä (dos sofás ilman määräistä artikkelia) → hay. Jos olisi 'los dos sofás que compramos' → están.","rule":"hay_cantidad"},
  {"id":4,"type":"gap","question":"Täydennä: 'El profesor no ___ en el aula ahora mismo.'","context":"El profesor no está en el aula ahora mismo, ha salido un momento.","options":["A) está","B) hay","C) es","D) tiene"],"correct":"A","explanation":"Tietyn henkilön (el profesor — määrätty) sijainti → estar. 'No hay el profesor' on kielioppivirhe.","rule":"estar_persona"}
]$json$::jsonb, 1.0);

-- ─── GRAMMAR · B · preterite_imperfect ───────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('grammar', 'B', 'preterite_imperfect', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Ayer ___ al cine con mis amigos.'","context":"Ayer fui al cine con mis amigos para ver la nueva película.","options":["A) fui","B) iba","C) he ido","D) voy"],"correct":"A","explanation":"Ayer = päättynyt, rajattu hetki → preteriti (fui). iba = imperfekti (kävin tapana).","rule":"preterito_accion_completada"},
  {"id":2,"type":"gap","question":"Täydennä: 'Cuando ___ pequeño, siempre jugaba en el parque.'","context":"Cuando era pequeño, siempre jugaba en el parque cerca de mi casa.","options":["A) era","B) fui","C) he sido","D) soy"],"correct":"A","explanation":"Taustakuvaus, tapa lapsena → imperfekti (era). fui olisi 'olin kerran pieni' = merkityksettömän.","rule":"imperfecto_edad_descripcion"},
  {"id":3,"type":"gap","question":"Täydennä: 'Mientras ___ la tele, sonó el teléfono.'","context":"Mientras veía la tele, sonó el teléfono en la cocina.","options":["A) veía","B) vi","C) he visto","D) veo"],"correct":"A","explanation":"Taustatoiminta (käynnissä oleva) → imperfekti. Etualan toiminto (soi) → preteriti (sonó).","rule":"imperfecto_accion_fondo"},
  {"id":4,"type":"gap","question":"Täydennä: 'El año pasado mi familia ___ a Barcelona de vacaciones.'","context":"El año pasado mi familia fue a Barcelona de vacaciones durante dos semanas.","options":["A) fue","B) iba","C) va","D) ha ido"],"correct":"A","explanation":"El año pasado + yksittäinen rajattu matka → preteriti. iba = kävi yleensä (toistuva).","rule":"preterito_tiempo_definido"}
]$json$::jsonb, 1.0),

('grammar', 'B', 'preterite_imperfect', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'De repente, ___ un ruido muy fuerte en la calle.'","context":"De repente, oímos un ruido muy fuerte en la calle y salimos a ver qué pasaba.","options":["A) oímos","B) oíamos","C) hemos oído","D) oíamos"],"correct":"A","explanation":"De repente + yksittäinen tapahtuma → preteriti. Imperfekti olisi kuultiin yleensä.","rule":"preterito_de_repente"},
  {"id":2,"type":"gap","question":"Täydennä: 'Mi abuela siempre me ___ cuentos antes de dormir.'","context":"Mi abuela siempre me contaba cuentos antes de dormir cuando era pequeña.","options":["A) contaba","B) contó","C) ha contado","D) cuenta"],"correct":"A","explanation":"Siempre + toistuva lapsuusmuisto → imperfekti. Preteriti tarkoittaisi 'kertoi (tasan kerran)'.","rule":"imperfecto_habitual"},
  {"id":3,"type":"gap","question":"Täydennä: 'Anoche ___ hasta las tres de la mañana.'","context":"Anoche estudié hasta las tres de la mañana para el examen.","options":["A) estudié","B) estudiaba","C) estudio","D) he estudiado"],"correct":"A","explanation":"Anoche (mennyt yö) + rajattu kesto → preteriti. estudiaba kuvaisi taustaa ('opiskelin kun...').","rule":"preterito_duracion_acabada"},
  {"id":4,"type":"gap","question":"Täydennä: 'La casa ___ grande y tenía cinco dormitorios.'","context":"La casa era grande y tenía cinco dormitorios, un salón enorme y un jardín.","options":["A) era","B) fue","C) es","D) ha sido"],"correct":"A","explanation":"Talon kuvailu menneisyydessä (tausta) → imperfekti. Fue olisi 'oli kerran, mutta ei enää' (muutospiste).","rule":"imperfecto_descripcion"}
]$json$::jsonb, 1.0);

-- ─── GRAMMAR · C · ser_estar ─────────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('grammar', 'C', 'ser_estar', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Este plátano no ___ maduro todavía.'","context":"Este plátano no está maduro todavía, tiene la cáscara demasiado verde.","options":["A) está","B) es","C) hay","D) tiene"],"correct":"A","explanation":"Kypsyysaste on muuttuva tila → estar. 'Es maduro' tarkoittaisi 'henkisesti aikuinen/kypsä' (henkilöstä).","rule":"estar_estado_cambiante"},
  {"id":2,"type":"gap","question":"Täydennä: 'Los libros que me recomendaste ___ muy aburridos.'","context":"Los libros que me recomendaste son muy aburridos, no los he podido terminar.","options":["A) son","B) están","C) hay","D) tienen"],"correct":"A","explanation":"Kirjojen luonne (pysyvä ominaisuus) → ser aburrido. Están aburridos tarkoittaisi 'kirjat ovat pitkästyneitä' (absurdi).","rule":"ser_caracteristica_objeto"},
  {"id":3,"type":"gap","question":"Täydennä: 'La fiesta ___ en casa de Ana este sábado.'","context":"La fiesta es en casa de Ana este sábado por la noche.","options":["A) es","B) está","C) hay","D) tiene"],"correct":"A","explanation":"Tapahtuman (fiesta) paikka → ser, ei estar. Estar tapahtumasta = kielioppivirhe.","rule":"ser_evento_lugar"},
  {"id":4,"type":"gap","question":"Täydennä: 'Después del accidente, ___ un mes en el hospital.'","context":"Después del accidente, estuvo un mes en el hospital en observación.","options":["A) estuvo","B) fue","C) era","D) hubo"],"correct":"A","explanation":"Sijainti määrätyssä paikassa (sairaala) → estar myös preteritissä. Fue tässä tarkoittaisi 'meni sairaalaan' (suunta).","rule":"estar_preterito_ubicacion"}
]$json$::jsonb, 1.0),

('grammar', 'C', 'ser_estar', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Ese chico ___ aburrido y nunca quiere hacer nada divertido.'","context":"Ese chico es aburrido y nunca quiere hacer nada divertido los fines de semana.","options":["A) es","B) está","C) hay","D) tiene"],"correct":"A","explanation":"Luonteenpiirre (tylsä ihmisenä) → ser aburrido. 'Está aburrido' = hän on juuri nyt pitkästynyt (tilapäinen mieliala).","rule":"ser_vs_estar_aburrido"},
  {"id":2,"type":"gap","question":"Täydennä: 'La ventana ___ rota desde ayer.'","context":"La ventana está rota desde ayer, hay que llamar a un cristalero.","options":["A) está","B) es","C) hay","D) tiene"],"correct":"A","explanation":"Partisiippi joka kuvaa tilaa (rikottu, lopputulos) → estar. Ser + rota = 'ikkuna on rikki luonteeltaan' — järjetön.","rule":"estar_participio_resultado"},
  {"id":3,"type":"gap","question":"Täydennä: 'Hoy la reunión ___ en la sala B, no en la sala A.'","context":"Hoy la reunión es en la sala B, no en la sala A como normalmente.","options":["A) es","B) está","C) hay","D) tiene"],"correct":"A","explanation":"Tapahtuman (reunión) paikka → ser. Yleinen virhe: 'la reunión está en sala B' — kokous ei 'sijaitse' vaan 'tapahtuu'.","rule":"ser_evento_lugar_c"},
  {"id":4,"type":"gap","question":"Täydennä: 'María ___ muy guapa hoy con ese vestido nuevo.'","context":"María está muy guapa hoy con ese vestido nuevo que compró ayer.","options":["A) está","B) es","C) hay","D) tiene"],"correct":"A","explanation":"Tilapäinen ulkonäkö tänään → estar guapa (näyttää kauniilta juuri nyt). Es guapa = on kaunis (pysyvä ominaisuus).","rule":"ser_vs_estar_guapo"}
]$json$::jsonb, 1.0);

-- ─── GRAMMAR · C · subjunctive ───────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('grammar', 'C', 'subjunctive', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Ojalá ___ buen tiempo este fin de semana.'","context":"Ojalá haga buen tiempo este fin de semana para ir a la playa.","options":["A) haga","B) hace","C) hará","D) hizo"],"correct":"A","explanation":"Ojalá vaatii AINA subjunktiivin. Hace (indikatiivi) on yleinen virhe.","rule":"ojala_subjuntivo"},
  {"id":2,"type":"gap","question":"Täydennä: 'Mi madre quiere que ___ los deberes antes de cenar.'","context":"Mi madre quiere que hagamos los deberes antes de cenar en la mesa.","options":["A) hagamos","B) hacemos","C) hicimos","D) haremos"],"correct":"A","explanation":"Querer que + toinen subjekti → subjunktiivi. Hacemos (indikatiivi) olisi virhe.","rule":"querer_que_subjuntivo"},
  {"id":3,"type":"gap","question":"Täydennä: 'Te llamo para que me ___ cuándo llega el tren.'","context":"Te llamo para que me digas cuándo llega el tren de Sevilla.","options":["A) digas","B) dices","C) decías","D) dijiste"],"correct":"A","explanation":"Para que + tarkoitus → subjunktiivi aina. Para que dices (indikatiivi) olisi virhe.","rule":"para_que_subjuntivo"},
  {"id":4,"type":"gap","question":"Täydennä: 'Es importante que los jóvenes ___ el medio ambiente.'","context":"Es importante que los jóvenes cuiden el medio ambiente para el futuro.","options":["A) cuiden","B) cuidan","C) cuidarán","D) cuidaron"],"correct":"A","explanation":"Es importante que + subjunktiivi (impersoonallinen arvoilmaisu). cuidan olisi kielioppivirhe.","rule":"es_importante_subjuntivo"}
]$json$::jsonb, 1.0),

('grammar', 'C', 'subjunctive', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Espero que ___ pronto de España.'","context":"Espero que vuelvas pronto de España para contarme todo el viaje.","options":["A) vuelvas","B) vuelves","C) volverás","D) volviste"],"correct":"A","explanation":"Esperar que + toinen subjekti → subjunktiivi. Vuelves on klassinen virhe (indikatiivi tunneilmaisun kanssa).","rule":"esperar_que_subjuntivo"},
  {"id":2,"type":"gap","question":"Täydennä: 'Dudo que Juan ___ a la fiesta esta noche.'","context":"Dudo que Juan venga a la fiesta esta noche porque tiene mucho trabajo.","options":["A) venga","B) viene","C) vendrá","D) vino"],"correct":"A","explanation":"Dudar que + epävarmuus → subjunktiivi. Viene on virhe — epäilys laukaisee aina subjunktiivin.","rule":"dudar_que_subjuntivo"},
  {"id":3,"type":"gap","question":"Täydennä: 'Cuando ___ mayor, seré médico.'","context":"Cuando sea mayor, seré médico para ayudar a la gente.","options":["A) sea","B) soy","C) seré","D) era"],"correct":"A","explanation":"Cuando + tulevaisuuden tapahtuma → subjunktiivi. Cuando sea mayor = kun olen iso. Cuando soy mayor on virhe.","rule":"cuando_futuro_subjuntivo"},
  {"id":4,"type":"gap","question":"Täydennä: 'No creo que ___ una buena idea ir ahora.'","context":"No creo que sea una buena idea ir ahora, está lloviendo mucho.","options":["A) sea","B) es","C) será","D) era"],"correct":"A","explanation":"No creer que (kielto + mielipide) → subjunktiivi. 'No creo que es' on tavallinen virhe.","rule":"no_creer_que_subjuntivo"}
]$json$::jsonb, 1.0);

-- ─── GRAMMAR · C · conditional ───────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('grammar', 'C', 'conditional', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Me ___ viajar a Argentina algún día.'","context":"Me gustaría viajar a Argentina algún día para conocer la Patagonia.","options":["A) gustaría","B) gustaba","C) gustó","D) gusta"],"correct":"A","explanation":"Kohtelias toive / unelma → konditionaali (gustaría). Gustaba = piti yleensä (imperfekti).","rule":"condicional_deseo"},
  {"id":2,"type":"gap","question":"Täydennä: '¿___ ayudarme con esta pregunta, por favor?'","context":"¿Podrías ayudarme con esta pregunta, por favor? Es muy difícil.","options":["A) Podrías","B) Puedes","C) Podías","D) Pudiste"],"correct":"A","explanation":"Kohtelias pyyntö → konditionaali (podrías). Puedes on neutraali, podías imperfekti ('pystyitkö silloin').","rule":"condicional_peticion_cortes"},
  {"id":3,"type":"gap","question":"Täydennä: 'Dijo que ___ a las ocho, pero llegó tarde.'","context":"Dijo que vendría a las ocho, pero llegó tarde como siempre.","options":["A) vendría","B) venía","C) vino","D) viene"],"correct":"A","explanation":"Menneisyyden tulevaisuus (tulisi) → konditionaali. Venía (imperfekti) = yleensä, vino (preteriti) = tuli (realisoitunut).","rule":"condicional_futuro_pasado"},
  {"id":4,"type":"gap","question":"Täydennä: 'En tu lugar, yo ___ con un abogado.'","context":"En tu lugar, yo hablaría con un abogado antes de firmar nada.","options":["A) hablaría","B) hablo","C) hablé","D) hablaba"],"correct":"A","explanation":"Hypoteettinen neuvo ('jos olisin sinä') → konditionaali. Hablo olisi 'puhun (realisti)'.","rule":"condicional_hipotesis"}
]$json$::jsonb, 1.0),

('grammar', 'C', 'conditional', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: '¿Me ___ decir dónde está la estación?'","context":"Perdone, ¿me podría decir dónde está la estación de tren más cercana?","options":["A) podría","B) puede","C) podía","D) pudo"],"correct":"A","explanation":"Erittäin kohtelias pyyntö muukalaiselle → konditionaali. Puede on kohtelias mutta vähemmän muodollinen.","rule":"condicional_cortesia_formal"},
  {"id":2,"type":"gap","question":"Täydennä: 'Yo que tú, ___ al médico cuanto antes.'","context":"Yo que tú, iría al médico cuanto antes porque esa tos no es normal.","options":["A) iría","B) voy","C) iba","D) fui"],"correct":"A","explanation":"'Yo que tú' + neuvo → konditionaali aina. Voy = menen (realisti), fui/iba = kävin.","rule":"condicional_consejo"},
  {"id":3,"type":"gap","question":"Täydennä: 'Prometió que ___ todos los gastos del viaje.'","context":"Prometió que pagaría todos los gastos del viaje a Italia.","options":["A) pagaría","B) pagaba","C) pagó","D) paga"],"correct":"A","explanation":"Lupaus menneisyydessä tulevaisuudesta → konditionaali. Classic imperfekti/konditionaali-virhe: pagaba = maksoi yleensä.","rule":"condicional_promesa_pasado"},
  {"id":4,"type":"gap","question":"Täydennä: 'Sería bueno que ___ más ejercicio.'","context":"Sería bueno que hicieras más ejercicio para mejorar tu salud.","options":["A) hicieras","B) haces","C) hiciste","D) harías"],"correct":"A","explanation":"Sería bueno que + subjunktiivin imperfekti (irreaalinen). Harías (konditionaali) että-lauseessa on virhe.","rule":"seria_bueno_que_subj_imp"}
]$json$::jsonb, 1.0);

-- ─── GRAMMAR · C · preterite_imperfect ───────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('grammar', 'C', 'preterite_imperfect', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Cuando llegué a casa, mi hermano ___ la tele.'","context":"Cuando llegué a casa, mi hermano veía la tele tranquilamente en el sofá.","options":["A) veía","B) vio","C) ha visto","D) ve"],"correct":"A","explanation":"Tausta (oli katsomassa, käynnissä) → imperfekti. Vio = katsoi (rajattu).","rule":"imperfecto_fondo_llegada"},
  {"id":2,"type":"gap","question":"Täydennä: 'Ayer ___ dos kilómetros antes de desayunar.'","context":"Ayer corrí dos kilómetros antes de desayunar para empezar el día con energía.","options":["A) corrí","B) corría","C) corro","D) he corrido"],"correct":"A","explanation":"Ayer + rajattu matka (2 km) → preteriti. Corría imperfektinä = juoksin yleensä.","rule":"preterito_ayer_cantidad"},
  {"id":3,"type":"gap","question":"Täydennä: 'Cuando ___ estudiante, vivía con cinco compañeros.'","context":"Cuando era estudiante, vivía con cinco compañeros en un piso muy grande.","options":["A) era","B) fui","C) soy","D) he sido"],"correct":"A","explanation":"Menneisyyden vaihe (opiskelija-aika) → imperfekti. Fui = olin kerran opiskelija (absoluuttisen merkityksen vaihto).","rule":"imperfecto_etapa_vida"},
  {"id":4,"type":"gap","question":"Täydennä: 'De repente ___ a llover y nos mojamos.'","context":"De repente empezó a llover y nos mojamos todos en la calle.","options":["A) empezó","B) empezaba","C) empieza","D) ha empezado"],"correct":"A","explanation":"De repente + muutospiste → preteriti. Empezaba olisi 'oli alkamassa' (keskeneräinen, tausta).","rule":"preterito_de_repente_c"}
]$json$::jsonb, 1.0),

('grammar', 'C', 'preterite_imperfect', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Mi abuela ___ muchísimo y tenía mucha paciencia con nosotros.'","context":"Mi abuela nos quería muchísimo y tenía mucha paciencia con nosotros.","options":["A) nos quería","B) nos quiso","C) nos ha querido","D) nos quiere"],"correct":"A","explanation":"Tunne/tila menneisyydessä (yleensä) → imperfekti. Quiso = päätti rakastaa/halusi (radikaalisti eri merkitys).","rule":"imperfecto_sentimiento_habitual"},
  {"id":2,"type":"gap","question":"Täydennä: 'El verano pasado ___ durante tres semanas en Italia.'","context":"El verano pasado estuvimos durante tres semanas en Italia viajando por el país.","options":["A) estuvimos","B) estábamos","C) estamos","D) hemos estado"],"correct":"A","explanation":"Rajattu kesto (tres semanas, päättynyt) → preteriti. Estábamos = olimme (taustana toiselle tapahtumalle).","rule":"preterito_duracion_delimitada"},
  {"id":3,"type":"gap","question":"Täydennä: 'Mientras ___ la cena, escuchábamos las noticias.'","context":"Mientras preparaba la cena, escuchábamos las noticias en la radio.","options":["A) preparaba","B) preparé","C) preparo","D) he preparado"],"correct":"A","explanation":"Mientras + samanaikainen taustatoiminta → imperfekti. Myös escuchábamos on imperfektissä (sama logiikka).","rule":"mientras_imperfecto_simultaneo"},
  {"id":4,"type":"gap","question":"Täydennä: 'Cuando era pequeño, ___ mucho miedo a los perros.'","context":"Cuando era pequeño, tenía mucho miedo a los perros grandes del barrio.","options":["A) tenía","B) tuve","C) tengo","D) he tenido"],"correct":"A","explanation":"Pitkäkestoinen tila lapsuudessa → imperfekti. Tuve miedo = pelästyin kerran (hetkellinen).","rule":"imperfecto_estado_prolongado"}
]$json$::jsonb, 1.0);

-- ─── GRAMMAR · C · pronouns ──────────────────────────────────
INSERT INTO exercise_bank (mode, level, topic, language, payload, quality_score) VALUES
('grammar', 'C', 'pronouns', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'El libro ___ me prestaste es muy interesante.'","context":"El libro que me prestaste la semana pasada es muy interesante.","options":["A) que","B) quien","C) donde","D) lo cual"],"correct":"A","explanation":"Relatiivipronomini esineelle → que (ei quien — quien käy vain henkilöille preposition jälkeen). Kielletty virhe: que-pronomiini ei saa jäädä pois.","rule":"relativo_que_objeto"},
  {"id":2,"type":"gap","question":"Täydennä: 'Ese es el profesor ___ te hablé ayer.'","context":"Ese es el profesor de quien te hablé ayer en la cafetería.","options":["A) de quien","B) que","C) de que","D) el cual"],"correct":"A","explanation":"Prepositio + henkilö → de quien (ei de que). Que ilman prepositiota olisi 'el profesor que...' (eri merkitys, suora obj.).","rule":"relativo_prep_quien"},
  {"id":3,"type":"gap","question":"Täydennä: 'Te ___ he dicho mil veces.'","context":"Te lo he dicho mil veces: cierra la puerta cuando salgas.","options":["A) lo","B) le","C) la","D) les"],"correct":"A","explanation":"Epäsuora + suora: te (epäsuora) tulee ensin, sitten lo (suora neutri). 'Te la' vaatisi feminiinin.","rule":"pronombres_orden_te_lo"},
  {"id":4,"type":"gap","question":"Täydennä: 'La ciudad ___ nací tiene medio millón de habitantes.'","context":"La ciudad donde nací tiene medio millón de habitantes en total.","options":["A) donde","B) que","C) en la cual","D) la que"],"correct":"A","explanation":"Paikan relatiivi → donde (luontevin puhutussa). En la cual on muodollisempi. Que vaatisi 'en la que'.","rule":"relativo_lugar_donde"}
]$json$::jsonb, 1.0),

('grammar', 'C', 'pronouns', 'spanish', $json$[
  {"id":1,"type":"gap","question":"Täydennä: 'Me encantan estas gafas. ¿___ puedo probar?'","context":"Me encantan estas gafas. ¿Me las puedo probar un momento?","options":["A) Me las","B) Me los","C) Te las","D) Las me"],"correct":"A","explanation":"Me (itse) + las (gafas, feminiinifluraali). Jäsenjärjestys: epäsuora ennen suoraa. 'Las me' on virhe.","rule":"pronombres_clitico_orden"},
  {"id":2,"type":"gap","question":"Täydennä: '¿Le has dado el regalo a María? — Sí, ya ___ di.'","context":"¿Le has dado el regalo a María? — Sí, ya se lo di esta mañana.","options":["A) se lo","B) le lo","C) lo le","D) le"],"correct":"A","explanation":"Le + lo → se lo (pakollinen sääntö: le/les muuttuu se:ksi kun seuraa lo/la/los/las). 'Le lo' on kielioppivirhe.","rule":"pronombres_se_lo"},
  {"id":3,"type":"gap","question":"Täydennä: 'Son los amigos ___ fuimos al concierto.'","context":"Son los amigos con los que fuimos al concierto en Barcelona.","options":["A) con los que","B) que","C) quienes","D) los cuales"],"correct":"A","explanation":"Prepositio + henkilöt (monikko) → con los que (tavallinen) tai con quienes (muodollinen). 'Que' ilman prepositiota olisi virhe.","rule":"relativo_prep_los_que"},
  {"id":4,"type":"gap","question":"Täydennä: 'Hay muchos sitios ___ visitar en Granada.'","context":"Hay muchos sitios que visitar en Granada, sobre todo la Alhambra.","options":["A) que","B) donde","C) los que","D) cuales"],"correct":"A","explanation":"'sitios que visitar' = infinitiiviklausuuli, vaatii que:n. Yleinen virhe jättää que pois: *sitios tienes que visitar.","rule":"relativo_que_infinitivo"}
]$json$::jsonb, 1.0);
